const html = $input.first().json.data || $input.first().json.body || '';

// Parse Schema.org JSON-LD
const scripts = [];
const regex = /<script[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
let match;
while ((match = regex.exec(html)) !== null) {
  try {
    scripts.push(JSON.parse(match[1].trim()));
  } catch (e) { }
}

const knownTypes = ['Organization','LocalBusiness','Restaurant','FAQ','FAQPage','Product','BreadcrumbList','WebSite'];
const found = new Set();

function extractTypes(obj) {
  if (!obj || typeof obj !== 'object') return;
  if (Array.isArray(obj)) { obj.forEach(extractTypes); return; }
  const type = obj['@type'];
  if (type) {
    const types = Array.isArray(type) ? type : [type];
    types.forEach(t => { if (knownTypes.includes(t)) found.add(t); });
  }
  if (obj['@graph']) obj['@graph'].forEach(extractTypes);
}
scripts.forEach(extractTypes);

const foundArr = Array.from(found);
const missing = knownTypes.filter(t => !found.has(t));

return [{ json: { schema: { found: foundArr, missing, has_faq_schema: found.has('FAQ') || found.has('FAQPage') }, html } }];

const html = $input.first().json.html || '';
const branche = $('Webhook').first().json.body.branche || '';
const stad = $('Webhook').first().json.body.stad || '';

const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : '';

const metaMatch = html.match(/<meta[^>]*name\s*=\s*["']description["'][^>]*content\s*=\s*["']([\s\S]*?)["'][^>]*\/?>/i)
  || html.match(/<meta[^>]*content\s*=\s*["']([\s\S]*?)["'][^>]*name\s*=\s*["']description["'][^>]*\/?>/i);
const meta_description = metaMatch ? metaMatch[1].trim() : '';

const headings = [];
const hRegex = /<(h[1-6])[^>]*>([\s\S]*?)<\/\1>/gi;
let hMatch;
while ((hMatch = hRegex.exec(html)) !== null) {
  headings.push({ level: parseInt(hMatch[1][1]), text: hMatch[2].replace(/<[^>]*>/g, '').trim() });
}
const h1 = headings.find(h => h.level === 1);
const h1Text = h1 ? h1.text : '';
const h1Lower = h1Text.toLowerCase();

return [{ json: {
  ...$input.first().json,
  meta: {
    title, meta_description, meta_length: meta_description.length,
    h1: h1Text,
    h1_contains_location: h1Lower.includes(branche.toLowerCase()) || h1Lower.includes(stad.toLowerCase()),
    headings_hierarchy: headings.length > 0 && headings[0].level === 1,
    has_canonical: /<link[^>]*rel\s*=\s*["']canonical["']/i.test(html),
    has_og_tags: /<meta[^>]*property\s*=\s*["']og:/i.test(html)
  }
} }];

const html = $input.first().json.html || '';
const platforms = [
  { name: 'wordpress', sigs: [/wp-content\//i, /wp-includes\//i] },
  { name: 'shopify', sigs: [/cdn\.shopify\.com/i, /Shopify\.theme/i] },
  { name: 'wix', sigs: [/static\.wixstatic\.com/i, /_wix_browser_sess/i] },
  { name: 'squarespace', sigs: [/squarespace-cdn/i, /sqsp\./i] }
];
let platform = 'custom', confidence = 'low';
for (const p of platforms) {
  const matches = p.sigs.filter(s => s.test(html)).length;
  if (matches > 0) { platform = p.name; confidence = matches >= 2 ? 'high' : 'medium'; break; }
}

const { schema, meta } = $input.first().json;
return [{ json: { schema, meta, platform: { platform, confidence } } }];
